import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import api from '../../services/api';
import '../../styles/storekeeper/storekeeper-exports.css';

const StorekeeperExports = () => {
  const { user } = useAuth();
  const [exports, setExports] = useState([]);
  const [products, setProducts] = useState([]);
  const [ponds, setPonds] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showForm, setShowForm] = useState(false);

  const [filters, setFilters] = useState({
    productId: '',
    pondId: '',
    startDate: '',
    endDate: '',
  });

  const [formData, setFormData] = useState({
    productId: '',
    quantity: '',
    unitPrice: '',
    pondId: '',
    exportReason: '',
    note: '',
    exportDate: new Date().toISOString().split('T')[0],
  });

  useEffect(() => {
    loadExports();
    loadProducts();
    loadPonds();
  }, []);

  const loadExports = async () => {
    try {
      setLoading(true);
      setError(null);
      const params = new URLSearchParams();
      
      if (filters.productId) params.append('productId', filters.productId);
      if (filters.pondId) params.append('pondId', filters.pondId);
      if (filters.startDate) params.append('startDate', filters.startDate);
      if (filters.endDate) params.append('endDate', filters.endDate);

      const response = await api.get(`/inventory/exports?${params}`);
      setExports(response.data.data || []);
    } catch (err) {
      setError('Lỗi tải dữ liệu xuất kho');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const loadProducts = async () => {
    try {
      const response = await api.get('/inventory/products');
      setProducts(response.data.data || []);
    } catch (err) {
      console.error('Lỗi tải sản phẩm:', err);
    }
  };

  const loadPonds = async () => {
    try {
      const response = await api.get('/ponds');
      setPonds(response.data.data || []);
    } catch (err) {
      console.error('Lỗi tải danh sách ao:', err);
    }
  };

  const handleFilterChange = (e) => {
    const { name, value } = e.target;
    setFilters(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleFilterSubmit = (e) => {
    e.preventDefault();
    loadExports();
  };

  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (!formData.productId || !formData.quantity) {
        setError('Vui lòng điền đầy đủ thông tin: sản phẩm và số lượng');
        return;
      }

      const payload = {
        productId: parseInt(formData.productId),
        quantity: parseFloat(formData.quantity),
        unitPrice: formData.unitPrice ? parseFloat(formData.unitPrice) : null,
        pondId: formData.pondId ? parseInt(formData.pondId) : null,
        exportReason: formData.exportReason || null,
        note: formData.note || null,
        exportDate: formData.exportDate,
      };

      const response = await api.post('/inventory/exports', payload);
      
      if (response.data.success) {
        setFormData({
          productId: '',
          quantity: '',
          unitPrice: '',
          pondId: '',
          exportReason: '',
          note: '',
          exportDate: new Date().toISOString().split('T')[0],
        });
        setShowForm(false);
        setError(null);
        loadExports();
      }
    } catch (err) {
      setError('Lỗi tạo phiếu xuất kho: ' + (err.response?.data?.message || err.message));
      console.error(err);
    }
  };

  const getProductName = (productId) => {
    const product = products.find(p => p.product_id === productId);
    return product ? product.product_name : 'N/A';
  };

  const getProductCode = (productId) => {
    const product = products.find(p => p.product_id === productId);
    return product ? product.product_code : 'N/A';
  };

  const getPondName = (pondId) => {
    const pond = ponds.find(p => p.pond_id === pondId);
    return pond ? pond.pond_name : 'N/A';
  };

  if (loading) {
    return (
      <div className="storekeeper-exports-container">
        <div className="loading-spinner">Đang tải...</div>
      </div>
    );
  }

  return (
    <div className="storekeeper-exports-container">
      <div className="storekeeper-exports-header">
        <h2>📤 Xuất Kho</h2>
        <button 
          className="btn-primary"
          onClick={() => setShowForm(!showForm)}
        >
          {showForm ? '✕ Đóng' : '➕ Xuất Kho Mới'}
        </button>
      </div>

      {error && <div className="alert alert-error">{error}</div>}

      {showForm && (
        <div className="storekeeper-exports__form-container">
          <form onSubmit={handleSubmit} className="storekeeper-exports__form">
            <h3>Tạo Phiếu Xuất Kho</h3>
            
            <div className="storekeeper-exports__form-row">
              <div className="form-group">
                <label>Sản phẩm *</label>
                <select
                  name="productId"
                  value={formData.productId}
                  onChange={handleFormChange}
                  className="form-input"
                  required
                >
                  <option value="">-- Chọn sản phẩm --</option>
                  {products.map(p => (
                    <option key={p.product_id} value={p.product_id}>
                      {p.product_code} - {p.product_name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label>Ngày Xuất *</label>
                <input
                  type="date"
                  name="exportDate"
                  value={formData.exportDate}
                  onChange={handleFormChange}
                  className="form-input"
                  required
                />
              </div>
            </div>

            <div className="storekeeper-exports__form-row">
              <div className="form-group">
                <label>Số Lượng *</label>
                <input
                  type="number"
                  name="quantity"
                  value={formData.quantity}
                  onChange={handleFormChange}
                  placeholder="VD: 50"
                  step="0.01"
                  className="form-input"
                  required
                />
              </div>

              <div className="form-group">
                <label>Đơn Giá</label>
                <input
                  type="number"
                  name="unitPrice"
                  value={formData.unitPrice}
                  onChange={handleFormChange}
                  placeholder="VD: 50000 (tùy chọn)"
                  step="0.01"
                  className="form-input"
                />
              </div>
            </div>

            <div className="storekeeper-exports__form-row">
              <div className="form-group">
                <label>Ao Nuôi</label>
                <select
                  name="pondId"
                  value={formData.pondId}
                  onChange={handleFormChange}
                  className="form-input"
                >
                  <option value="">-- Chọn ao (tùy chọn) --</option>
                  {ponds.map(p => (
                    <option key={p.pond_id} value={p.pond_id}>
                      {p.pond_code} - {p.pond_name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label>Lý Do Xuất</label>
                <select
                  name="exportReason"
                  value={formData.exportReason}
                  onChange={handleFormChange}
                  className="form-input"
                >
                  <option value="">-- Chọn lý do --</option>
                  <option value="FEED">Cho ăn</option>
                  <option value="TREATMENT">Xử lý bệnh</option>
                  <option value="MAINTENANCE">Bảo trì</option>
                  <option value="OTHER">Khác</option>
                </select>
              </div>
            </div>

            <div className="form-group">
              <label>Ghi Chú</label>
              <textarea
                name="note"
                value={formData.note}
                onChange={handleFormChange}
                placeholder="Nhập ghi chú thêm (tùy chọn)"
                className="form-input"
                rows="3"
              />
            </div>

            <div className="storekeeper-exports__form-actions">
              <button type="submit" className="btn-primary">
                💾 Lưu Xuất Kho
              </button>
              <button
                type="button"
                className="btn-secondary"
                onClick={() => setShowForm(false)}
              >
                ✕ Hủy
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="storekeeper-exports__filters">
        <form onSubmit={handleFilterSubmit} className="storekeeper-exports__filter-form">
          <div className="storekeeper-exports__filter-row">
            <div className="form-group">
              <label>Sản phẩm</label>
              <select
                name="productId"
                value={filters.productId}
                onChange={handleFilterChange}
                className="form-input"
              >
                <option value="">-- Tất cả sản phẩm --</option>
                {products.map(p => (
                  <option key={p.product_id} value={p.product_id}>
                    {p.product_code} - {p.product_name}
                  </option>
                ))}
              </select>
            </div>

            <div className="form-group">
              <label>Ao Nuôi</label>
              <select
                name="pondId"
                value={filters.pondId}
                onChange={handleFilterChange}
                className="form-input"
              >
                <option value="">-- Tất cả ao --</option>
                {ponds.map(p => (
                  <option key={p.pond_id} value={p.pond_id}>
                    {p.pond_code} - {p.pond_name}
                  </option>
                ))}
              </select>
            </div>

            <div className="form-group">
              <label>Từ Ngày</label>
              <input
                type="date"
                name="startDate"
                value={filters.startDate}
                onChange={handleFilterChange}
                className="form-input"
              />
            </div>

            <div className="form-group">
              <label>Đến Ngày</label>
              <input
                type="date"
                name="endDate"
                value={filters.endDate}
                onChange={handleFilterChange}
                className="form-input"
              />
            </div>

            <button type="submit" className="btn-secondary">
              🔍 Lọc
            </button>
          </div>
        </form>
      </div>

      <div className="storekeeper-exports__table-container">
        <table className="storekeeper-exports__table">
          <thead>
            <tr>
              <th>Ngày Xuất</th>
              <th>Mã Sản Phẩm</th>
              <th>Tên Sản Phẩm</th>
              <th>Số Lượng</th>
              <th>Ao Nuôi</th>
              <th>Lý Do</th>
              <th>Đơn Giá</th>
              <th>Thành Tiền</th>
              <th>Người Xuất</th>
              <th>Ghi Chú</th>
            </tr>
          </thead>
          <tbody>
            {exports.length === 0 ? (
              <tr>
                <td colSpan="10" className="text-center">
                  Không có dữ liệu xuất kho
                </td>
              </tr>
            ) : (
              exports.map(exp => (
                <tr key={exp.export_id}>
                  <td>{new Date(exp.export_date).toLocaleDateString('vi-VN')}</td>
                  <td className="font-mono">{exp.product_code}</td>
                  <td>{exp.product_name}</td>
                  <td className="text-right">{exp.quantity.toLocaleString('vi-VN', { maxFractionDigits: 2 })}</td>
                  <td>{exp.pond_code ? `${exp.pond_code} - ${exp.pond_name}` : '-'}</td>
                  <td>{exp.export_reason || '-'}</td>
                  <td className="text-right">{exp.unit_price ? exp.unit_price.toLocaleString('vi-VN', { maxFractionDigits: 0 }) + ' ₫' : '-'}</td>
                  <td className="text-right font-bold">{exp.total_amount ? exp.total_amount.toLocaleString('vi-VN', { maxFractionDigits: 0 }) + ' ₫' : '-'}</td>
                  <td>{exp.created_by_name || 'N/A'}</td>
                  <td className="text-muted">{exp.note || '-'}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default StorekeeperExports;
